var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"네? 부대로 정상 출근하신다고요? 정말 고향에 가지 않아도 괜찮으신 겁니까?","JPN":"はい？　部隊に通常出勤ですか？　実家に戻らなくて本当に大丈夫ですか？","ENG":"What? You're coming to work today? Are you sure you don't need to go see your family?","TWN":"咦？您說要讓部隊正常出動？您不回故鄉真的沒關係嗎？"},"stage":{"bg":"BAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"지금이라도 중장님께 말씀을 드리면, 바로 휴가를 내 주실 겁니다.","JPN":"今なら、中将に報告すればすぐに休暇がもらえるはずです。","ENG":"I'm sure it's not too late for you to request leave with the Lieutenant General.","TWN":"現在還來得及，只要跟中將大人說一下，中將大人應該馬上會批准休假的。"},"stage":{"bg":"BAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아냐, 됐어.","JPN":"いや、いいんだ。","ENG":"It's fine.","TWN":"不，不用了。"},"stage":{"bg":"BAR","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그리고 이 얘기는 중장님께는 비밀로 해줬으면 좋겠어.","JPN":"それと、この話は中将には内緒にしてほしい。","ENG":"And I'd appreciate it if you could keep this a secret from the Lieutenant General.","TWN":"還有，這件事我希望你能對中將保密。"},"stage":{"bg":"BAR","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"많이 바쁘실 테니 말이야.","JPN":"忙しいようだしな。","ENG":"I'm sure she's busy enough as it is.","TWN":"畢竟她很忙。"},"stage":{"bg":"BAR","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BAR","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"바텐더. 늘 마시던 걸로.","JPN":"マスター、いつもの。","ENG":"Bartender. Give me the usual.","TWN":"酒保，老樣子。"},"stage":{"bg":"BAR","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MASTER_NPC_NULL_NULL","text":{"KOREA":"자네가 늘 마시던 거? 밀크셰이크 말인가?","JPN":"お前のいつものって何だ？　ミルクセーキか？","ENG":"The usual? You mean a milkshake?","TWN":"老樣子？你是指奶昔嗎？"},"stage":{"bg":"BAR","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"로망이 없구만. 보는 눈도 있는데 이런 대사는 멋있게 좀 받아줘야 하는 거 아닌가?","JPN":"ロマンがないな。他の客もいるんだし、もう少しうまく言い返してくれてもいいんじゃないか。","ENG":"Come on, don't kill the vibe. I've got eyes on me. Can't you just go with the flow?","TWN":"你還真是不浪漫啊，旁邊還有人看著呢，這種時候不是應該把台詞帥氣地接下去嗎？"},"stage":{"bg":"BAR","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MASTER_NPC_NULL_NULL","text":{"KOREA":"몇 년째 팁도 한 푼 안 내는 수전노 주제에 바라는 것도 많군.","JPN":"何年もチップすら払わない守銭奴のくせに、文句を言うんじゃない。","ENG":"Says the cheapskate who hasn't tipped for years.","TWN":"一個幾年都沒給過小費的守財奴，要求倒是很多。"},"stage":{"bg":"BAR","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASTER_NPC_NULL_NULL","text":{"KOREA":"자네 딸의 부탁만 아니었으면 당장 쫓아냈을 거야.","JPN":"お前の娘の頼みじゃなかったら、さっさと追い出したい所だ。","ENG":"If it weren't for your daughter's request, I would've kicked you out a long time ago.","TWN":"要不是看在你女兒的面子上，我早就把你趕出去了。"},"stage":{"bg":"BAR","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"하하, 아빠가 항상 딸의 도움만 받는군.","JPN":"はは、父親になって娘に助けられてばかりだな。","ENG":"Hah hah, I guess my daughter's always helping out her old man.","TWN":"哈哈，當爸爸的總是會沾女兒的光呢。"},"stage":{"bg":"BAR","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그나저나 이 친구는 너무 많이 마신 것 같은데? 완전히 맛이 갔는걸?","JPN":"ところで、こいつ飲みすぎじゃないか？　完全に酔っ払ってるぞ？","ENG":"By the way, this fella seems to have outdone himself. He's wasted.","TWN":"話說這位朋友是不是喝多了？有點不太對勁啊？"},"stage":{"bg":"BAR","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이봐, 무슨 일이라도 있는 건가?","JPN":"なぁ、何かあったのか？","ENG":"Hey buddy, something wrong?","TWN":"嘿，你怎麼了嗎？"},"stage":{"bg":"BAR","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그런 거 없어. 그냥 목이 마를 뿐이야.","JPN":"何もないんだ。ただ喉が乾いただけだ。","ENG":"Everything's fine... I'm just thirsty.","TWN":"沒什麼。只是有點口渴了。"},"stage":{"bg":"BAR","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그리고 용병인 것 같은데...... 함부로 말 걸지 마.","JPN":"それに、傭兵のようだが……俺に軽々しく話しかけるな。","ENG":"You look like a mercenary... Don't call me buddy...","TWN":"然後你看起來好像是個傭兵……不要隨便跟我搭話。"},"stage":{"bg":"BAR","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"난 용병을 싫어해.","JPN":"俺は傭兵が嫌いなんだよ。","ENG":"I hate you mercs.","TWN":"我討厭傭兵。"},"stage":{"bg":"BAR","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그래? 편견이 심한 친구로군.","JPN":"そうか？　酷い偏見を持っているんだな。","ENG":"Is that right? You sound like one prejudiced fella.","TWN":"是嗎？真是位偏見嚴重的朋友呢。"},"stage":{"bg":"BAR","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};